Review this CDC (Clock Domain Crossing) code:
module cdc_fast_to_slow(input clk_fast, input clk_slow, input data_in, output data_out);
  reg data_q;
  always @(posedge clk_fast) data_q <= data_in;

  reg sync1, sync2;
  always @(posedge clk_slow) begin
    sync1 <= data_q;
    sync2 <= sync1;
  end
  assign data_out = sync2;
endmodule

